# Generated by anthropic (claude-sonnet-4-5)
# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

properties([
    parameters([
        string(name: 'BUILD_COMMAND', defaultValue: 'echo "No build command specified"', description: 'Custom build command to execute'),
        string(name: 'TEST_COMMAND', defaultValue: 'echo "No test command specified"', description: 'Custom test command to execute'),
        string(name: 'DEPLOYMENT_COMMAND', defaultValue: 'echo "No deployment command specified"', description: 'Custom deployment command to execute'),
        text(name: 'PRE_BUILD_SCRIPT', defaultValue: '', description: 'Multi-line pre-build script (optional)'),
        text(name: 'POST_BUILD_SCRIPT', defaultValue: '', description: 'Multi-line post-build script (optional)'),
        choice(name: 'ENVIRONMENT', choices: ['dev', 'staging', 'production'], description: 'Target environment'),
        booleanParam(name: 'SKIP_TESTS', defaultValue: false, description: 'Skip test execution'),
        booleanParam(name: 'SKIP_DEPLOYMENT', defaultValue: false, description: 'Skip deployment step'),
        string(name: 'WORKING_DIRECTORY', defaultValue: '.', description: 'Working directory for commands'),
        string(name: 'BUILD_TIMEOUT', defaultValue: '60', description: 'Build timeout in minutes'),
        text(name: 'ENVIRONMENT_VARIABLES', defaultValue: '', description: 'Environment variables (KEY=VALUE, one per line)'),
        string(name: 'SHELL_EXECUTOR', defaultValue: '/bin/bash', description: 'Shell executor path'),
        booleanParam(name: 'VERBOSE_OUTPUT', defaultValue: true, description: 'Enable verbose output'),
        text(name: 'CLEANUP_SCRIPT', defaultValue: '', description: 'Cleanup script to run after build (optional)')
    ])
])

pipeline {
    agent any
    
    options {
        timeout(time: params.BUILD_TIMEOUT.toInteger(), unit: 'MINUTES')
        timestamps()
        buildDiscarder(logRotator(numToKeepStr: '10'))
    }
    
    environment {
        ENVIRONMENT = "${params.ENVIRONMENT}"
        VERBOSE = "${params.VERBOSE_OUTPUT}"
    }
    
    stages {
        stage('Setup') {
            steps {
                script {
                    echo "=== Pipeline Configuration ==="
                    echo "Environment: ${params.ENVIRONMENT}"
                    echo "Working Directory: ${params.WORKING_DIRECTORY}"
                    echo "Skip Tests: ${params.SKIP_TESTS}"
                    echo "Skip Deployment: ${params.SKIP_DEPLOYMENT}"
                    echo "Build Timeout: ${params.BUILD_TIMEOUT} minutes"
                    echo "Shell Executor: ${params.SHELL_EXECUTOR}"
                    
                    if (params.ENVIRONMENT_VARIABLES?.trim()) {
                        echo "=== Custom Environment Variables ==="
                        echo params.ENVIRONMENT_VARIABLES
                    }
                }
            }
        }
        
        stage('Pre-Build') {
            when {
                expression { params.PRE_BUILD_SCRIPT?.trim() }
            }
            steps {
                script {
                    echo "=== Executing Pre-Build Script ==="
                    dir(params.WORKING_DIRECTORY) {
                        executeCustomScript(params.PRE_BUILD_SCRIPT, 'pre-build')
                    }
                }
            }
        }
        
        stage('Build') {
            steps {
                script {
                    echo "=== Executing Build Command ==="
                    dir(params.WORKING_DIRECTORY) {
                        executeCommand(params.BUILD_COMMAND, 'build')
                    }
                }
            }
        }
        
        stage('Test') {
            when {
                expression { !params.SKIP_TESTS }
            }
            steps {
                script {
                    echo "=== Executing Test Command ==="
                    dir(params.WORKING_DIRECTORY) {
                        executeCommand(params.TEST_COMMAND, 'test')
                    }
                }
            }
        }
        
        stage('Post-Build') {
            when {
                expression { params.POST_BUILD_SCRIPT?.trim() }
            }
            steps {
                script {
                    echo "=== Executing Post-Build Script ==="
                    dir(params.WORKING_DIRECTORY) {
                        executeCustomScript(params.POST_BUILD_SCRIPT, 'post-build')
                    }
                }
            }
        }
        
        stage('Deploy') {
            when {
                expression { !params.SKIP_DEPLOYMENT }
            }
            steps {
                script {
                    echo "=== Executing Deployment Command ==="
                    echo "Deploying to: ${params.ENVIRONMENT}"
                    dir(params.WORKING_DIRECTORY) {
                        executeCommand(params.DEPLOYMENT_COMMAND, 'deployment')
                    }
                }
            }
        }
    }
    
    post {
        always {
            script {
                if (params.CLEANUP_SCRIPT?.trim()) {
                    echo "=== Executing Cleanup Script ==="
                    dir(params.WORKING_DIRECTORY) {
                        try {
                            executeCustomScript(params.CLEANUP_SCRIPT, 'cleanup')
                        } catch (Exception e) {
                            echo "Cleanup script failed: ${e.message}"
                        }
                    }
                }
                
                echo "=== Pipeline Execution Summary ==="
                echo "Status: ${currentBuild.result ?: 'SUCCESS'}"
                echo "Duration: ${currentBuild.durationString}"
            }
        }
        success {
            echo "Pipeline completed successfully!"
        }
        failure {
            echo "Pipeline failed. Check logs for details."
        }
        unstable {
            echo "Pipeline completed with unstable status."
        }
    }
}

def executeCommand(String command, String stageName) {
    def envVars = buildEnvironmentVariables()
    def shellScript = buildShellScript(command, envVars)
    
    if (params.VERBOSE_OUTPUT) {
        echo "Executing ${stageName} command:"
        echo command
    }
    
    def result = sh(
        script: shellScript,
        returnStatus: true
    )
    
    if (result != 0) {
        error("${stageName} command failed with exit code: ${result}")
    }
}

def executeCustomScript(String script, String stageName) {
    def envVars = buildEnvironmentVariables()
    def shellScript = buildShellScript(script, envVars)
    
    if (params.VERBOSE_OUTPUT) {
        echo "Executing ${stageName} script:"
        echo script
    }
    
    def result = sh(
        script: shellScript,
        returnStatus: true
    )
    
    if (result != 0) {
        error("${stageName} script failed with exit code: ${result}")
    }
}

def buildEnvironmentVariables() {
    def envVars = [:]
    
    if (params.ENVIRONMENT_VARIABLES?.trim()) {
        params.ENVIRONMENT_VARIABLES.split('\n').each { line ->
            def trimmedLine = line.trim()
            if (trimmedLine && trimmedLine.contains('=')) {
                def parts = trimmedLine.split('=', 2)
                if (parts.length == 2) {
                    envVars[parts[0].trim()] = parts[1].trim()
                }
            }
        }
    }
    
    envVars['BUILD_NUMBER'] = env.BUILD_NUMBER
    envVars['BUILD_ID'] = env.BUILD_ID
    envVars['JOB_NAME'] = env.JOB_NAME
    envVars['WORKSPACE'] = env.WORKSPACE
    envVars['TARGET_ENVIRONMENT'] = params.ENVIRONMENT
    
    return envVars
}

def buildShellScript(String command, Map envVars) {
    def script = "#!${params.SHELL_EXECUTOR}\n"
    script += "set -e\n"
    
    if (params.VERBOSE_OUTPUT) {
        script += "set -x\n"
    }
    
    envVars.each { key, value ->
        script += "export ${key}='${value}'\n"
    }
    
    script += "\n${command}\n"
    
    return script
}